+            Some(json!({"size": 1048576, "lineCount": 50000})),
+            "large_file",
+        ),
+        (
+            Some(json!({"matchCount": 42, "fileCount": 7})),
+            "grep_result",
+        ),
+        (
+            Some(json!({"linesChanged": 5, "hunks": 2})),
+            "edit_result",
+        ),
