+
+    for (details, label) in &detail_cases {
+        let event = AgentEvent::ToolExecutionEnd {
+            tool_call_id: format!("tc-{label}"),
+            tool_name: "bash".to_string(),
+            result: ToolOutput {
+                content: vec![ContentBlock::Text(TextContent::new("output"))],
+                details: details.clone(),
+                is_error: false,
+            },
